using System.ComponentModel;
using System.Net;
using System.Text.Json;

namespace ResearchAgent;

/// <summary>
/// Provides web search capability to the agent.
/// Uses the Google Custom Search JSON API when configured,
/// otherwise falls back to a simulated search for demonstration.
/// </summary>
public sealed class WebSearcher
{
    private readonly HttpClient _http = new();
    private readonly string? _googleApiKey;
    private readonly string? _googleCxId;

    public WebSearcher()
    {
        _googleApiKey = Environment.GetEnvironmentVariable("GOOGLE_API_KEY");
        _googleCxId = Environment.GetEnvironmentVariable("GOOGLE_CX_ID");
    }

    [Description("Searches the web for information about a query and returns the top results with titles, snippets, and URLs.")]
    public async Task<string> SearchWeb(
        [Description("The search query to look up on the web")] string query)
    {
        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  🌐 Searching: \"{query}\"");
        Console.ResetColor();

        if (!string.IsNullOrEmpty(_googleApiKey) && !string.IsNullOrEmpty(_googleCxId))
        {
            return await SearchWithGoogleAsync(query);
        }

        return SimulateSearch(query);
    }

    private async Task<string> SearchWithGoogleAsync(string query)
    {
        var encodedQuery = WebUtility.UrlEncode(query);
        var url = $"https://www.googleapis.com/customsearch/v1?key={_googleApiKey}&cx={_googleCxId}&q={encodedQuery}&num=5";

        try
        {
            var json = await _http.GetStringAsync(url);
            using var doc = JsonDocument.Parse(json);
            var items = doc.RootElement.GetProperty("items");

            var results = new List<string>();
            foreach (var item in items.EnumerateArray().Take(5))
            {
                var title = item.GetProperty("title").GetString();
                var snippet = item.GetProperty("snippet").GetString();
                var link = item.GetProperty("link").GetString();
                results.Add($"- **{title}**\n  {snippet}\n  Source: {link}");
            }

            return $"Search results for \"{query}\":\n\n{string.Join("\n\n", results)}";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Falling back to simulated results.\n\n{SimulateSearch(query)}";
        }
    }

    private static string SimulateSearch(string query)
    {
        var q = query.ToLowerInvariant();

        // Provide plausible simulated results based on query keywords
        var results = new List<(string Title, string Snippet, string Url)>();

        if (q.Contains("quantum"))
        {
            results.AddRange([
                ("Quantum Computing - Wikipedia", "Quantum computing uses quantum-mechanical phenomena such as superposition and entanglement to perform computation. A quantum computer uses qubits instead of classical bits.", "https://en.wikipedia.org/wiki/Quantum_computing"),
                ("What Is Quantum Computing? - IBM", "Quantum computing harnesses quantum mechanics to solve complex problems faster than classical computers. IBM offers cloud-based quantum computing services via IBM Quantum.", "https://www.ibm.com/quantum"),
                ("Google Quantum AI", "Google achieved quantum supremacy in 2019 with its Sycamore processor, completing a task in 200 seconds that would take classical supercomputers 10,000 years.", "https://quantumai.google/"),
            ]);
        }
        else if (q.Contains("climate") || q.Contains("warming") || q.Contains("environment"))
        {
            results.AddRange([
                ("Climate Change - NASA", "Global temperatures have risen 1.1°C since pre-industrial times. NASA tracks climate indicators including CO2 levels, sea level rise, and Arctic ice extent.", "https://climate.nasa.gov/"),
                ("IPCC Sixth Assessment Report", "The IPCC AR6 report confirms human influence on climate is unequivocal. Limiting warming to 1.5°C requires CO2 emissions to reach net zero by 2050.", "https://www.ipcc.ch/assessment-report/ar6/"),
                ("Renewable Energy Growth - IEA", "Renewable energy capacity additions hit a record in 2023, led by solar PV. The IEA projects renewables will supply 35% of global electricity by 2025.", "https://www.iea.org/reports/renewables"),
            ]);
        }
        else if (q.Contains("ai") || q.Contains("artificial intelligence") || q.Contains("machine learning"))
        {
            results.AddRange([
                ("Artificial Intelligence - Stanford HAI", "Stanford's Institute for Human-Centered AI reports that AI adoption in enterprises doubled from 2017 to 2023, with generative AI being the fastest-growing segment.", "https://hai.stanford.edu/"),
                ("The State of AI Report 2024", "Key findings: foundation models continue to scale, AI safety research is accelerating, and regulatory frameworks are emerging across major economies.", "https://www.stateof.ai/"),
                ("OpenAI Research", "OpenAI develops frontier AI models including GPT-4o and o1, focusing on general-purpose AI systems that benefit humanity.", "https://openai.com/research"),
            ]);
        }
        else
        {
            results.AddRange([
