+/// <summary>
+/// Provides web search capability to the agent.
+/// Uses the Google Custom Search JSON API when configured,
+/// otherwise falls back to a simulated search for demonstration.
+/// </summary>
+public sealed class WebSearcher
+{
+    private readonly HttpClient _http = new();
+    private readonly string? _googleApiKey;
+    private readonly string? _googleCxId;
+
+    public WebSearcher()
+    {
+        _googleApiKey = Environment.GetEnvironmentVariable("GOOGLE_API_KEY");
+        _googleCxId = Environment.GetEnvironmentVariable("GOOGLE_CX_ID");
+    }
+
+    [Description("Searches the web for information about a query and returns the top results with titles, snippets, and URLs.")]
+    public async Task<string> SearchWeb(
+        [Description("The search query to look up on the web")] string query)
+    {
+        Console.ForegroundColor = ConsoleColor.DarkYellow;
+        Console.WriteLine($"  🌐 Searching: \"{query}\"");
+        Console.ResetColor();
+
+        if (!string.IsNullOrEmpty(_googleApiKey) && !string.IsNullOrEmpty(_googleCxId))
+        {
+            return await SearchWithGoogleAsync(query);
+        }
+
+        return SimulateSearch(query);
+    }
+
+    private async Task<string> SearchWithGoogleAsync(string query)
+    {
+        var encodedQuery = WebUtility.UrlEncode(query);
+        var url = $"https://www.googleapis.com/customsearch/v1?key={_googleApiKey}&cx={_googleCxId}&q={encodedQuery}&num=5";
+
+        try
+        {
+            var json = await _http.GetStringAsync(url);
+            using var doc = JsonDocument.Parse(json);
+            var items = doc.RootElement.GetProperty("items");
+
+            var results = new List<string>();
+            foreach (var item in items.EnumerateArray().Take(5))
+            {
+                var title = item.GetProperty("title").GetString();
+                var snippet = item.GetProperty("snippet").GetString();
+                var link = item.GetProperty("link").GetString();
+                results.Add($"- **{title}**\n  {snippet}\n  Source: {link}");
+            }
+
+            return $"Search results for \"{query}\":\n\n{string.Join("\n\n", results)}";
+        }
+        catch (Exception ex)
