using System.ComponentModel;

namespace ResearchAgent;

/// <summary>
/// Provides a note-taking tool for the agent to record and retrieve research findings.
/// </summary>
public sealed class Notebook
{
    private readonly List<Note> _notes = [];

    [Description("Saves a research note with a title and content. Use this to record key findings from web searches.")]
    public string AddNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content of the note — key facts, data points, or quotes from search results")] string content)
    {
        var note = new Note(title, content, DateTimeOffset.UtcNow);
        _notes.Add(note);

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📝 Note added: \"{title}\"");
        Console.ResetColor();

        return $"Note #{_notes.Count} saved: \"{title}\"";
    }

    [Description("Retrieves all saved research notes. Use this to review your findings before writing the final summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        Console.ForegroundColor = ConsoleColor.DarkYellow;
        Console.WriteLine($"  📋 Reviewing {_notes.Count} note(s)");
        Console.ResetColor();

        var formatted = _notes.Select((n, i) =>
            $"Note #{i + 1}: {n.Title}\n{n.Content}");

        return $"Research notes ({_notes.Count} total):\n\n{string.Join("\n\n---\n\n", formatted)}";
    }

    public void Clear() => _notes.Clear();

    private sealed record Note(string Title, string Content, DateTimeOffset Timestamp);
}

